-- local SHADOW DB from which packages/data/src/database.types.ts is generated
-- (see scripts/db/build-shadow-db.mjs) and to classify migration files
-- (docs/v3/fl2-apply-manifest.md).
--
-- Apply context (shadow only): a Supabase local stack, as a superuser role,
-- with check_function_bodies = off. Functions precede tables deliberately.
-- ============================================================================

set check_function_bodies = off;

-- ============ extensions ============
create extension if not exists "citext" with schema "public";
create extension if not exists "pg_stat_statements" with schema "extensions";
create extension if not exists "pgcrypto" with schema "extensions";
create extension if not exists "uuid-ossp" with schema "extensions";

-- ============ enum types ============
create type public.app_role as enum ('owner', 'manager', 'rider', 'customer', 'support', 'cashier', 'promoter');
create type public.saved_item_status as enum ('active', 'expired', 'soft_deleted', 'restored');
create type public.user_address_label as enum ('home', 'office', 'shop', 'warehouse', 'alternative_1', 'alternative_2', 'legacy_imported_1', 'legacy_imported_2', 'legacy_imported_3', 'legacy_imported_4');
create type public.user_engagement_event_type as enum ('cart_abandoned', 'cart_resumed', 'saved_item_added', 'saved_item_about_to_expire', 'saved_item_restored', 'saved_item_expired', 'checkout_started', 'checkout_resumed', 'checkout_abandoned_at_step', 'kyc_incomplete_after_signup', 'comeback_visit');

-- ============ sequences ============
create sequence if not exists public.search_index_outbox_id_seq as bigint increment by 1 minvalue 1 maxvalue 9223372036854775807 start with 1 cache 1;
create sequence if not exists public.staff_audit_logs_id_seq as bigint increment by 1 minvalue 1 maxvalue 9223372036854775807 start with 1 cache 1;

