CREATE OR REPLACE FUNCTION public.add_audit_log(p_action text, p_entity_type text, p_entity_id text DEFAULT NULL::text, p_target_user_id uuid DEFAULT NULL::uuid, p_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  if auth.uid() is null then
    raise exception 'Not authenticated';
  end if;

  insert into public.audit_logs (
    actor_id,
    target_user_id,
    entity_type,
    entity_id,
    action,
    metadata
  )
  values (
    auth.uid(),
    p_target_user_id,
    p_entity_type,
    p_entity_id,
    p_action,
    coalesce(p_metadata, '{}'::jsonb)
  );
end;
$function$
;
CREATE OR REPLACE FUNCTION public.add_audit_log_v2(p_action text, p_entity_type text, p_entity_id text DEFAULT NULL::text, p_old_values jsonb DEFAULT NULL::jsonb, p_new_values jsonb DEFAULT NULL::jsonb, p_reason text DEFAULT NULL::text, p_division text DEFAULT NULL::text, p_correlation_id uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_actor_id uuid := auth.uid();
  v_actor_role text;
  v_entity_id uuid;
  v_audit_id uuid;
begin
  -- Defence-in-depth: caller must be a staff member in some division
  -- to write audit logs. Customers cannot fabricate audit log rows.
  if not public.is_staff_in_any() then
    raise exception 'add_audit_log_v2: caller is not staff' using errcode = '42501';
  end if;

  -- Best-effort actor_role lookup from profiles. Audit log rows still
  -- write if the profile lookup fails (the action being audited is
  -- more important than the role attribution).
  begin
    select lower(coalesce(role, '')) into v_actor_role
    from public.profiles
    where id = v_actor_id
    limit 1;
  exception when others then
    v_actor_role := null;
  end;

  -- Defensive cast: audit_logs.entity_id is uuid on prod. Callers pass
  -- the entity id as text (TS-side type is string). Empty/invalid
  -- inputs degrade to NULL so the audit row still writes.
  begin
    v_entity_id := nullif(p_entity_id, '')::uuid;
  exception when others then
    v_entity_id := null;
  end;

  insert into public.audit_logs (
    action,
    actor_id,
    actor_role,
    entity_type,
    entity_id,
    old_values,
    new_values,
    reason,
    division,
    correlation_id,
    created_at
  ) values (
    p_action,
    v_actor_id,
    v_actor_role,
    p_entity_type,
    v_entity_id,
    p_old_values,
    p_new_values,
    p_reason,
    p_division,
    p_correlation_id,
    timezone('utc', now())
  )
  returning id into v_audit_id;

  return v_audit_id;
end;
$function$
;
CREATE OR REPLACE FUNCTION public.admin_force_reauth(p_user_id uuid)
 RETURNS profiles
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_profile public.profiles;
begin
  if not public.is_owner() then
    raise exception 'Only owners can force re-auth';
  end if;

  update public.profiles
  set force_reauth_after = now()
  where id = p_user_id
  returning * into v_profile;

  if v_profile.id is null then
    raise exception 'Profile not found';
  end if;

  return v_profile;
end;
$function$
;
CREATE OR REPLACE FUNCTION public.admin_set_profile_frozen(p_user_id uuid, p_is_frozen boolean)
 RETURNS profiles
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_profile public.profiles;
begin
  if not public.is_owner() then
    raise exception 'Only owners can freeze/unfreeze users';
  end if;

  update public.profiles
  set is_frozen = p_is_frozen
  where id = p_user_id
  returning * into v_profile;

  if v_profile.id is null then
    raise exception 'Profile not found';
  end if;

  return v_profile;
end;
$function$
;
CREATE OR REPLACE FUNCTION public.admin_set_profile_role(p_user_id uuid, p_role text)
 RETURNS profiles
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_profile public.profiles;
begin
  if not public.is_owner() then
    raise exception 'Only owners can change roles';
  end if;

  if p_role not in ('owner', 'manager', 'rider', 'support', 'staff') then
    raise exception 'Invalid role';
  end if;

  update public.profiles
  set role = p_role
  where id = p_user_id
  returning * into v_profile;

  if v_profile.id is null then
    raise exception 'Profile not found';
  end if;

  return v_profile;
end;
$function$
;
CREATE OR REPLACE FUNCTION public.care_append_expense_ledger()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
begin
  if new.approval_status in ('recorded', 'approved') then
    insert into public.care_finance_ledger (
      entry_type,
      source_table,
      source_id,
      booking_id,
      direction,
      amount,
      narration
    )
    values (
      'expense',
      'care_expenses',
      new.id,
      null,
      'outflow',
      new.amount,
      coalesce(new.description, 'Expense')
    )
    on conflict (source_table, source_id, direction) do nothing;
  end if;

  return new;
end;
$function$
;
