CREATE OR REPLACE FUNCTION public.care_order_item_set_line_total()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
begin
  new.quantity := greatest(coalesce(new.quantity, 1), 1);
  new.unit_price_snapshot := coalesce(new.unit_price_snapshot, 0);
  new.urgent_fee_snapshot := coalesce(new.urgent_fee_snapshot, 0);
  new.line_total := (new.quantity * new.unit_price_snapshot) + new.urgent_fee_snapshot;
  return new;
end;
$function$
;
CREATE OR REPLACE FUNCTION public.care_queue_picked_up_payment_email()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  v_booking public.care_bookings%rowtype;
  v_settings record;
  v_request_id uuid;
  v_amount_due numeric(12,2);
  v_subject text;
begin
  if tg_op <> 'UPDATE' then
    return new;
  end if;

  if coalesce(old.status, '') = coalesce(new.status, '') then
    return new;
  end if;

  if lower(coalesce(new.status, '')) <> 'picked_up' then
    return new;
  end if;

  perform public.care_recalculate_booking_totals(new.id);

  select *
  into v_booking
  from public.care_bookings
  where id = new.id;

  if v_booking.id is null then
    return new;
  end if;

  if coalesce(v_booking.email, '') = '' then
    return new;
  end if;

  select
    id,
    payment_bank_name,
    payment_account_name,
    payment_account_number,
    payment_currency,
    payment_instructions,
    payment_support_email,
    payment_support_whatsapp,
    notification_sender_name,
    notification_reply_to_email
  into v_settings
  from public.care_settings
  order by id
  limit 1;

  v_amount_due := coalesce(v_booking.balance_due, 0);

  if v_amount_due <= 0 then
    return new;
  end if;

  if exists (
    select 1
    from public.care_payment_requests
    where booking_id = v_booking.id
      and request_kind = 'picked_up_payment_request'
  ) then
    return new;
  end if;

  insert into public.care_payment_requests (
    booking_id,
    request_kind,
    currency,
    amount_due,
    bank_name,
    account_name,
    account_number,
    instructions,
    recipient_email,
    status,
    payload
  )
  values (
    v_booking.id,
    'picked_up_payment_request',
    coalesce(v_settings.payment_currency, 'NGN'),
    v_amount_due,
    v_settings.payment_bank_name,
    v_settings.payment_account_name,
    v_settings.payment_account_number,
    v_settings.payment_instructions,
    v_booking.email,
    'queued',
    jsonb_build_object(
      'tracking_code', v_booking.tracking_code,
      'customer_name', v_booking.customer_name,
      'service_type', v_booking.service_type,
      'quoted_subtotal', coalesce(v_booking.quoted_subtotal, 0),
      'quoted_urgent_fee', coalesce(v_booking.quoted_urgent_fee, 0),
      'quoted_total', coalesce(v_booking.quoted_total, 0),
      'amount_paid', coalesce(v_booking.amount_paid, 0),
      'balance_due', coalesce(v_booking.balance_due, 0),
      'support_email', v_settings.payment_support_email,
      'support_whatsapp', v_settings.payment_support_whatsapp
    )
  )
  returning id into v_request_id;

  v_subject := 'Payment request for booking ' || coalesce(v_booking.tracking_code, '');

  insert into public.care_notification_queue (
    booking_id,
    payment_request_id,
    channel,
    template_key,
    recipient,
    subject,
    payload,
    status
  )
  values (
    v_booking.id,
    v_request_id,
    'email',
    'picked_up_payment_request',
    v_booking.email,
    v_subject,
    jsonb_build_object(
      'booking_id', v_booking.id,
      'tracking_code', v_booking.tracking_code,
      'customer_name', v_booking.customer_name,
      'customer_email', v_booking.email,
      'service_type', v_booking.service_type,
      'quoted_subtotal', coalesce(v_booking.quoted_subtotal, 0),
      'quoted_urgent_fee', coalesce(v_booking.quoted_urgent_fee, 0),
      'quoted_total', coalesce(v_booking.quoted_total, 0),
      'amount_paid', coalesce(v_booking.amount_paid, 0),
      'balance_due', coalesce(v_booking.balance_due, 0),
      'bank_name', v_settings.payment_bank_name,
      'account_name', v_settings.payment_account_name,
      'account_number', v_settings.payment_account_number,
      'payment_currency', coalesce(v_settings.payment_currency, 'NGN'),
      'payment_instructions', v_settings.payment_instructions,
      'support_email', v_settings.payment_support_email,
      'support_whatsapp', v_settings.payment_support_whatsapp,
      'notification_sender_name', v_settings.notification_sender_name,
      'notification_reply_to_email', v_settings.notification_reply_to_email
    ),
    'queued'
  );

  update public.care_bookings
  set
    payment_requested_at = now(),
    last_payment_email_queued_at = now()
  where id = v_booking.id;

  return new;
end;
$function$
;
