CREATE OR REPLACE FUNCTION public.care_recalculate_booking_totals(p_booking_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  v_subtotal numeric(12,2) := 0;
  v_urgent_fee numeric(12,2) := 0;
  v_total numeric(12,2) := 0;
  v_paid numeric(12,2) := 0;
  v_balance numeric(12,2) := 0;
  v_status text := 'unpaid';
begin
  select
    coalesce(sum(coalesce(quantity, 1) * coalesce(unit_price_snapshot, 0)), 0),
    coalesce(sum(coalesce(urgent_fee_snapshot, 0)), 0),
    coalesce(sum(coalesce(line_total, 0)), 0)
  into
    v_subtotal,
    v_urgent_fee,
    v_total
  from public.care_order_items
  where booking_id = p_booking_id;

  select
    coalesce(sum(coalesce(amount, 0)), 0)
  into
    v_paid
  from public.care_payments
  where booking_id = p_booking_id;

  v_balance := greatest(v_total - v_paid, 0);

  if v_total <= 0 and v_paid <= 0 then
    v_status := 'unpaid';
  elsif v_paid <= 0 then
    v_status := 'unpaid';
  elsif v_paid < v_total then
    v_status := 'part_paid';
  elsif v_paid = v_total then
    v_status := 'paid';
  elsif v_paid > v_total then
    v_status := 'overpaid';
  end if;

  update public.care_bookings
  set
    quoted_subtotal = coalesce(v_subtotal, 0),
    quoted_urgent_fee = coalesce(v_urgent_fee, 0),
    quoted_total = coalesce(v_total, 0),
    amount_paid = coalesce(v_paid, 0),
    balance_due = coalesce(v_balance, 0),
    payment_status = v_status
  where id = p_booking_id;
end;
$function$
;
CREATE OR REPLACE FUNCTION public.care_set_payment_request_no()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
begin
  if new.request_no is null or btrim(new.request_no) = '' then
    new.request_no :=
      'CPR-' ||
      to_char(now(), 'YYYYMMDD') ||
      '-' ||
      upper(substr(replace(gen_random_uuid()::text, '-', ''), 1, 8));
  end if;
  return new;
end;
$function$
;
