CREATE OR REPLACE FUNCTION public.create_care_booking(p_customer_name text, p_phone text, p_pickup_address text, p_pickup_date date, p_pickup_slot text, p_service_type text, p_email text DEFAULT NULL::text, p_item_summary text DEFAULT NULL::text, p_special_instructions text DEFAULT NULL::text)
 RETURNS TABLE(id uuid, tracking_code text, status text, created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_row public.care_bookings%rowtype;
  v_phone_normalized text;
begin
  if coalesce(length(trim(p_customer_name)), 0) < 2 then
    raise exception 'Customer name is required';
  end if;

  v_phone_normalized := public.normalize_phone(p_phone);

  if v_phone_normalized is null or length(v_phone_normalized) < 5 then
    raise exception 'Valid phone number is required';
  end if;

  if coalesce(length(trim(p_service_type)), 0) < 2 then
    raise exception 'Service type is required';
  end if;

  if coalesce(length(trim(p_pickup_address)), 0) < 5 then
    raise exception 'Pickup address is required';
  end if;

  if p_pickup_date is null then
    raise exception 'Pickup date is required';
  end if;

  if coalesce(length(trim(p_pickup_slot)), 0) < 2 then
    raise exception 'Pickup slot is required';
  end if;

  insert into public.care_bookings (
    customer_name,
    phone,
    phone_normalized,
    email,
    service_type,
    item_summary,
    pickup_address,
    pickup_date,
    pickup_slot,
    special_instructions
  )
  values (
    trim(p_customer_name),
    trim(p_phone),
    v_phone_normalized,
    nullif(trim(coalesce(p_email, '')), ''),
    trim(p_service_type),
    nullif(trim(coalesce(p_item_summary, '')), ''),
    trim(p_pickup_address),
    p_pickup_date,
    trim(p_pickup_slot),
    nullif(trim(coalesce(p_special_instructions, '')), '')
  )
  returning * into v_row;

  return query
  select
    v_row.id,
    v_row.tracking_code,
    v_row.status,
    v_row.created_at;
end;
$function$
;
