CREATE OR REPLACE FUNCTION public.enforce_marketplace_listing_cap()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_tier text;
  v_cap integer;
  v_count integer;
begin
  if new.vendor_id is null then
    return new;
  end if;

  select seller_tier into v_tier
    from public.marketplace_vendors
   where id = new.vendor_id;

  if v_tier is null then
    return new;
  end if;

  v_cap := public.marketplace_tier_listing_cap(v_tier);

  select count(*) into v_count
    from public.marketplace_products
   where vendor_id = new.vendor_id
     and id <> coalesce(new.id, '00000000-0000-0000-0000-000000000000'::uuid)
     and coalesce(status, 'active') in ('active', 'draft', 'pending_review');

  if v_count >= v_cap then
    raise exception 'marketplace_listing_cap_exceeded'
      using errcode = 'P0001',
            hint = format(
              'Seller is at the %s-tier listing limit (%s). Upgrade tier or remove a listing first.',
              v_tier,
              v_cap
            );
  end if;

  return new;
end;
$function$
;
CREATE OR REPLACE FUNCTION public.enqueue_search_index_op(p_collection text, p_document_id text, p_operation text, p_payload jsonb DEFAULT '{}'::jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
begin
  if p_collection is null or length(p_collection) = 0 then
    raise exception 'enqueue_search_index_op: collection required';
  end if;
  if p_document_id is null or length(p_document_id) = 0 then
    raise exception 'enqueue_search_index_op: document_id required';
  end if;
  if p_operation not in ('upsert', 'delete') then
    raise exception 'enqueue_search_index_op: invalid operation %', p_operation;
  end if;

  insert into public.search_index_outbox (collection, document_id, operation, payload)
  values (p_collection, p_document_id, p_operation, coalesce(p_payload, '{}'::jsonb));
end;
$function$
;
