CREATE OR REPLACE FUNCTION public.get_signal_feed(viewer_id uuid, limit_count integer DEFAULT 50, after_score numeric DEFAULT NULL::numeric, after_created_at timestamp with time zone DEFAULT NULL::timestamp with time zone)
 RETURNS TABLE(id uuid, kind text, source text, division text, priority text, title text, body text, action_url text, created_at timestamp with time zone, score numeric)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  with viewer as (
    select viewer_id as id
  ),
  priority_weights(priority, weight) as (
    values
      ('security'::text, 1.5::numeric),
      ('urgent', 1.3),
      ('warning', 1.1),
      ('info', 1.0),
      ('success', 1.0)
  ),
  cust_notif as (
    select
      cn.id,
      'notification'::text as kind,
      'customer'::text as source,
      coalesce(cn.division, 'account')::text as division,
      cn.priority,
      cn.title,
      cn.body,
      cn.action_url,
      cn.created_at
    from public.customer_notifications cn
    where cn.user_id = (select id from viewer)
      and cn.deleted_at is null
  ),
  cust_activity as (
    select
      ca.id,
      'activity'::text as kind,
      'customer'::text as source,
      ca.division,
      coalesce(nullif(ca.status, ''), 'info')::text as priority,
      ca.title,
      ca.description as body,
      ca.action_url,
      ca.created_at
    from public.customer_activity ca
    where ca.user_id = (select id from viewer)
      and ca.created_at >= now() - interval '30 days'
      and ca.archived_at is null
  ),
  unioned as (
    select * from cust_notif
    union all
    select * from cust_activity
  ),
  scored as (
    select
      u.id,
      u.kind,
      u.source,
      u.division,
      u.priority,
      u.title,
      u.body,
      u.action_url,
      u.created_at,
      coalesce(pw.weight, 1.0)
        * exp(- extract(epoch from now() - u.created_at) / 86400.0)
        as score
    from unioned u
    left join priority_weights pw on pw.priority = u.priority
  )
  select
    s.id,
    s.kind,
    s.source,
    s.division,
    s.priority,
    s.title,
    s.body,
    s.action_url,
    s.created_at,
    s.score
  from scored s
  where (after_score is null or s.score < after_score)
     or (
       after_score is not null
       and s.score = after_score
       and s.created_at < after_created_at
     )
  order by s.score desc, s.created_at desc
  limit greatest(coalesce(limit_count, 50), 1);
$function$
;
CREATE OR REPLACE FUNCTION public.handle_new_customer()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  insert into public.customer_profiles (id, email, full_name)
  values (new.id, new.email, coalesce(new.raw_user_meta_data->>'full_name', ''));

  insert into public.customer_wallets (user_id)
  values (new.id);

  insert into public.customer_preferences (user_id)
  values (new.id);

  insert into public.customer_notifications (user_id, title, body, category, action_url)
  values (
    new.id,
    'Your HenryCo account is ready',
    'The account is set up. Explore the services and manage everything from one dashboard.',
    'account',
    '/'
  );

  insert into public.customer_activity (user_id, division, activity_type, title, description)
  values (
    new.id,
    'account',
    'account_created',
    'Account created',
    'The unified HenryCo account has been set up.'
  );

  return new;
end;
$function$
;
