CREATE OR REPLACE FUNCTION public.prevent_owner_property_status_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  if auth.uid() is null then
    return new;
  end if;

  if public.is_property_staff() then
    return new;
  end if;

  if new.status is distinct from old.status then
    new.status := old.status;
  end if;

  if new.visibility is distinct from old.visibility then
    new.visibility := old.visibility;
  end if;

  return new;
end;
$function$
;
CREATE OR REPLACE FUNCTION public.protect_profile_sensitive_fields()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  if auth.uid() is null then
    raise exception 'Not authenticated';
  end if;

  -- Owners are allowed to update role/freeze/reauth fields
  if public.is_owner() then
    return new;
  end if;

  -- Non-owners cannot elevate themselves or unfreeze themselves
  if new.role is distinct from old.role then
    raise exception 'You cannot change your role';
  end if;

  if new.is_frozen is distinct from old.is_frozen then
    raise exception 'You cannot change frozen state';
  end if;

  if new.force_reauth_after is distinct from old.force_reauth_after then
    raise exception 'You cannot change re-auth state';
  end if;

  return new;
end;
$function$
;
CREATE OR REPLACE FUNCTION public.purge_completed_search_outbox(p_older_than interval DEFAULT '7 days'::interval)
