CREATE OR REPLACE FUNCTION public.support_assign_thread(p_thread_id uuid, p_assignee_id uuid, p_actor_id uuid DEFAULT NULL::uuid, p_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  v_old_assignee uuid;
begin
  select assigned_to into v_old_assignee
  from public.support_threads
  where id = p_thread_id;

  if not found then
    return jsonb_build_object('success', false, 'error', 'thread_not_found');
  end if;

  update public.support_threads
  set assigned_to = p_assignee_id,
      updated_at = timezone('utc', now())
  where id = p_thread_id;

  insert into public.support_thread_events (thread_id, event_type, actor_id, actor_type, old_value, new_value, metadata)
  values (
    p_thread_id, 'assignment',
    p_actor_id, 'staff',
    v_old_assignee::text, p_assignee_id::text,
    p_metadata
  );

  return jsonb_build_object('success', true, 'old_assignee', v_old_assignee, 'new_assignee', p_assignee_id);
end;
$function$
;
CREATE OR REPLACE FUNCTION public.support_log_event(p_thread_id uuid, p_event_type text, p_actor_id uuid DEFAULT NULL::uuid, p_actor_type text DEFAULT 'system'::text, p_old_value text DEFAULT NULL::text, p_new_value text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  v_event_id uuid;
begin
  insert into public.support_thread_events (thread_id, event_type, actor_id, actor_type, old_value, new_value, metadata)
  values (p_thread_id, p_event_type, p_actor_id, p_actor_type, p_old_value, p_new_value, p_metadata)
  returning id into v_event_id;

  return v_event_id;
end;
$function$
;
CREATE OR REPLACE FUNCTION public.support_staff_reply(p_thread_id uuid, p_staff_id uuid, p_body text, p_attachments jsonb DEFAULT '[]'::jsonb, p_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  v_thread record;
  v_message_id uuid;
  v_now timestamptz := timezone('utc', now());
begin
  -- Verify thread exists
  select id, user_id, subject, division, status
  into v_thread
  from public.support_threads
  where id = p_thread_id;

  if v_thread.id is null then
    return jsonb_build_object('success', false, 'error', 'thread_not_found');
  end if;

  -- Insert staff message
  insert into public.support_messages (thread_id, sender_id, sender_type, body, attachments, created_at)
  values (p_thread_id, p_staff_id, 'agent', p_body, p_attachments, v_now)
  returning id into v_message_id;

  -- Update thread status and timestamps
  update public.support_threads
  set status = case when status in ('open', 'awaiting_reply') then 'in_progress' else status end,
      staff_last_read_at = v_now,
      updated_at = v_now
  where id = p_thread_id;

  -- Log reply event
  insert into public.support_thread_events (thread_id, event_type, actor_id, actor_type, new_value, metadata)
  values (p_thread_id, 'staff_reply', p_staff_id, 'staff', left(p_body, 100),
    jsonb_build_object('message_id', v_message_id));

  -- Create customer notification
  insert into public.customer_notifications (
    user_id, division, title, body, category, priority,
    action_url, reference_type, reference_id
  ) values (
    v_thread.user_id,
    coalesce(v_thread.division, 'account'),
    'New reply on your support request',
    'Staff has responded to "' || left(coalesce(v_thread.subject, 'your request'), 60) || '"',
    'support', 'normal',
    '/support/' || p_thread_id,
    'support_thread', p_thread_id::text
  );

  -- Log customer activity
  insert into public.customer_activity (
    user_id, division, activity_type, title, description,
    status, reference_type, reference_id
  ) values (
    v_thread.user_id,
    coalesce(v_thread.division, 'account'),
    'support_reply_received',
    'Reply on: ' || coalesce(v_thread.subject, 'Support conversation'),
    'Staff responded to your support request.',
    'active',
    'support_thread', p_thread_id::text
  );

  return jsonb_build_object(
    'success', true,
    'message_id', v_message_id,
    'thread_status', (select status from public.support_threads where id = p_thread_id)
  );
end;
$function$
;
CREATE OR REPLACE FUNCTION public.support_update_thread_status(p_thread_id uuid, p_new_status text, p_actor_id uuid DEFAULT NULL::uuid, p_actor_type text DEFAULT 'staff'::text, p_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  v_old_status text;
  v_now timestamptz := timezone('utc', now());
begin
  -- Get current status
  select status into v_old_status
  from public.support_threads
  where id = p_thread_id;

  if v_old_status is null then
    return jsonb_build_object('success', false, 'error', 'thread_not_found');
  end if;

  if v_old_status = p_new_status then
    return jsonb_build_object('success', true, 'changed', false);
  end if;

  -- Update thread
  update public.support_threads
  set status = p_new_status,
      resolved_at = case when p_new_status = 'resolved' then v_now else resolved_at end,
      closed_at = case when p_new_status = 'closed' then v_now else closed_at end,
      updated_at = v_now
  where id = p_thread_id;

  -- Log event
  insert into public.support_thread_events (thread_id, event_type, actor_id, actor_type, old_value, new_value, metadata)
  values (p_thread_id, 'status_change', p_actor_id, p_actor_type, v_old_status, p_new_status, p_metadata);

  return jsonb_build_object('success', true, 'changed', true, 'old_status', v_old_status, 'new_status', p_new_status);
end;
$function$
;
CREATE OR REPLACE FUNCTION public.tg_workflow_targets_to_outbox()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  v_doc_id text;
  v_payload jsonb;
begin
  if (tg_op = 'DELETE') then
    v_doc_id := 'account:workflow:' || old.id::text;
    perform public.enqueue_search_index_op('hc_workflows', v_doc_id, 'delete', '{}'::jsonb);
    return old;
  end if;

  v_doc_id := 'account:workflow:' || new.id::text;

  -- Soft-delete: resolved rows are removed from index.
  if (new.resolved_at is not null) then
    perform public.enqueue_search_index_op('hc_workflows', v_doc_id, 'delete', '{}'::jsonb);
    return new;
  end if;

  v_payload := jsonb_build_object(
    'id', v_doc_id,
    'type', 'workflow',
    'division', new.division,
    'title', new.title,
    'summary', new.summary,
    'deep_link', new.deep_link,
    'role_visibility', jsonb_build_array('owner'),
    'trust_state', 'unknown',
    'created_at', extract(epoch from new.created_at)::bigint,
    'updated_at', extract(epoch from new.updated_at)::bigint,
    'tags', jsonb_build_array('workflow', new.workflow_key, new.urgency),
    'cta_label', new.cta_label,
    'due_at', new.due_at,
    'owner_user_id', new.user_id,
    'ranking_signals', jsonb_build_object(
      'workflow_urgency',
      case new.urgency
        when 'critical' then 1.0
        when 'high' then 0.75
        when 'normal' then 0.5
        else 0.25
      end
    )
  );

  perform public.enqueue_search_index_op('hc_workflows', v_doc_id, 'upsert', v_payload);
  return new;
end;
$function$
;
