CREATE OR REPLACE FUNCTION public.track_care_booking(p_tracking_code text, p_phone text DEFAULT NULL::text)
 RETURNS TABLE(tracking_code text, customer_name text, phone text, service_type text, pickup_address text, pickup_date date, pickup_slot text, special_instructions text, status text, created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_code text := upper(trim(coalesce(p_tracking_code, '')));
  v_phone text := regexp_replace(coalesce(p_phone, ''), '\D', '', 'g');
begin
  return query
  select
    b.tracking_code,
    b.customer_name,
    b.phone,
    b.service_type,
    b.pickup_address,
    b.pickup_date,
    b.pickup_slot,
    b.special_instructions,
    b.status,
    b.created_at
  from public.care_bookings b
  where upper(trim(coalesce(b.tracking_code, ''))) = v_code
    and (
      v_phone = ''
      or regexp_replace(coalesce(b.phone, ''), '\D', '', 'g') = v_phone
    )
  order by b.created_at desc
  limit 1;
end;
$function$
;
CREATE OR REPLACE FUNCTION public.update_thread_unread_counts()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE affected_thread_id UUID; customer_unread INTEGER; staff_unread INTEGER;
BEGIN
  affected_thread_id := NEW.thread_id;
  IF affected_thread_id IS NULL THEN RETURN NEW; END IF;
  SELECT COUNT(*) FILTER (WHERE m.is_read = FALSE AND m.sender_type IS DISTINCT FROM 'customer'),
         COUNT(*) FILTER (WHERE m.is_read = FALSE AND m.sender_type = 'customer')
  INTO customer_unread, staff_unread
  FROM public.support_messages m WHERE m.thread_id = affected_thread_id AND m.deleted_at IS NULL;
  UPDATE public.support_threads SET unread_count_customer = COALESCE(customer_unread, 0), unread_count_staff = COALESCE(staff_unread, 0) WHERE id = affected_thread_id;
  RETURN NEW;
END;
$function$
;
