CREATE OR REPLACE FUNCTION public.wallet_apply_tx(p_profile_id uuid, p_tx_type text, p_amount_kobo bigint, p_description text DEFAULT NULL::text, p_reference text DEFAULT NULL::text, p_order_id uuid DEFAULT NULL::uuid, p_created_by uuid DEFAULT NULL::uuid)
 RETURNS wallet_transactions
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  w public.wallets;
  tx public.wallet_transactions;
begin
  if p_amount_kobo <= 0 then
    raise exception 'Amount must be > 0';
  end if;

  insert into public.wallets(profile_id)
  values (p_profile_id)
  on conflict (profile_id) do nothing;

  select * into w from public.wallets where profile_id = p_profile_id for update;

  if lower(p_tx_type) = 'debit' then
    if w.balance_kobo < p_amount_kobo then
      raise exception 'Insufficient balance';
    end if;
    update public.wallets set balance_kobo = balance_kobo - p_amount_kobo where id = w.id;
  elsif lower(p_tx_type) = 'credit' then
    update public.wallets set balance_kobo = balance_kobo + p_amount_kobo where id = w.id;
  else
    raise exception 'Invalid tx_type: %', p_tx_type;
  end if;

  insert into public.wallet_transactions(wallet_id, profile_id, tx_type, amount_kobo, description, reference, order_id, created_by)
  values (w.id, p_profile_id, lower(p_tx_type), p_amount_kobo, p_description, p_reference, p_order_id, p_created_by)
  returning * into tx;

  return tx;
end;
$function$
;
