-- ============ views ============
create or replace view public.care_finance_summary with (security_invoker=on) as  SELECT COALESCE(sum(
        CASE
            WHEN direction = 'inflow'::text THEN amount
            ELSE 0::numeric
        END), 0::numeric) AS total_inflow,
    COALESCE(sum(
        CASE
            WHEN direction = 'outflow'::text THEN amount
            ELSE 0::numeric
        END), 0::numeric) AS total_outflow,
    COALESCE(sum(
        CASE
            WHEN direction = 'inflow'::text THEN amount
            ELSE 0::numeric
        END), 0::numeric) - COALESCE(sum(
        CASE
            WHEN direction = 'outflow'::text THEN amount
            ELSE 0::numeric
        END), 0::numeric) AS balance
   FROM care_finance_ledger;
create or replace view public.care_finance_monthly_summary with (security_invoker=on) as  WITH monthly_inflow AS (
         SELECT date_trunc('month'::text, care_finance_ledger.created_at)::date AS month_start,
            COALESCE(sum(care_finance_ledger.amount), 0::numeric) AS inflow
           FROM care_finance_ledger
          WHERE care_finance_ledger.division = 'care'::text AND care_finance_ledger.direction = 'inflow'::text
          GROUP BY (date_trunc('month'::text, care_finance_ledger.created_at)::date)
        ), monthly_outflow AS (
         SELECT date_trunc('month'::text, care_finance_ledger.created_at)::date AS month_start,
            COALESCE(sum(care_finance_ledger.amount), 0::numeric) AS outflow
           FROM care_finance_ledger
          WHERE care_finance_ledger.division = 'care'::text AND care_finance_ledger.direction = 'outflow'::text
          GROUP BY (date_trunc('month'::text, care_finance_ledger.created_at)::date)
        ), months AS (
         SELECT monthly_inflow.month_start
           FROM monthly_inflow
        UNION
         SELECT monthly_outflow.month_start
           FROM monthly_outflow
        )
 SELECT m.month_start,
    COALESCE(i.inflow, 0::numeric) AS inflow,
    COALESCE(o.outflow, 0::numeric) AS outflow,
    COALESCE(i.inflow, 0::numeric) - COALESCE(o.outflow, 0::numeric) AS net_profit
   FROM months m
     LEFT JOIN monthly_inflow i ON i.month_start = m.month_start
     LEFT JOIN monthly_outflow o ON o.month_start = m.month_start
  ORDER BY m.month_start DESC;
create or replace view public.care_staff_expense_monthly_summary with (security_invoker=on) as  SELECT date_trunc('month'::text, created_at)::date AS month_start,
    created_by,
    COALESCE(created_by_role, 'staff'::text) AS created_by_role,
    count(*) AS expense_count,
    COALESCE(sum(amount), 0::numeric) AS total_expense
   FROM care_expenses e
  WHERE (COALESCE(approval_status, 'recorded'::text) = ANY (ARRAY['approved'::text, 'recorded'::text])) AND COALESCE(division, 'care'::text) = 'care'::text
  GROUP BY (date_trunc('month'::text, created_at)::date), created_by, (COALESCE(created_by_role, 'staff'::text))
  ORDER BY (date_trunc('month'::text, created_at)::date) DESC, (COALESCE(sum(amount), 0::numeric)) DESC;
create or replace view public.care_category_expense_monthly_summary with (security_invoker=on) as  SELECT date_trunc('month'::text, created_at)::date AS month_start,
    category,
    count(*) AS expense_count,
    COALESCE(sum(amount), 0::numeric) AS total_expense
   FROM care_expenses e
  WHERE (COALESCE(approval_status, 'recorded'::text) = ANY (ARRAY['approved'::text, 'recorded'::text])) AND COALESCE(division, 'care'::text) = 'care'::text
  GROUP BY (date_trunc('month'::text, created_at)::date), category
  ORDER BY (date_trunc('month'::text, created_at)::date) DESC, (COALESCE(sum(amount), 0::numeric)) DESC;
create or replace view public.user_address_summary with (security_invoker=on) as  SELECT id,
    user_id,
    label,
    full_name,
    phone,
    country,
    state,
    city,
    street,
    postal_code,
    coordinates_lat,
    coordinates_lng,
    formatted_address,
    kyc_verified,
    is_default,
    created_at,
    updated_at
   FROM user_addresses;
create or replace view public.studio_client_invoices_v with (security_invoker=on) as  SELECT i.id,
    i.project_id,
    i.milestone_id,
    i.client_user_id,
    i.normalized_email,
    i.invoice_number,
    i.amount_kobo,
    i.currency,
    i.description,
    i.due_date,
    i.status,
    i.invoice_token,
    i.issued_at,
    i.paid_at,
    i.created_at,
    i.updated_at,
    COALESCE(payment_summary.payment_count, 0) AS payment_count,
    payment_summary.last_submitted_at,
    payment_summary.last_payment_status,
    payment_summary.last_payment_id
   FROM studio_invoices i
     LEFT JOIN LATERAL ( SELECT count(*)::integer AS payment_count,
            max(p.submitted_at) AS last_submitted_at,
            ( SELECT studio_payments.status
                   FROM studio_payments
                  WHERE studio_payments.invoice_id = i.id
                  ORDER BY studio_payments.submitted_at DESC NULLS LAST
                 LIMIT 1) AS last_payment_status,
            ( SELECT studio_payments.id
                   FROM studio_payments
                  WHERE studio_payments.invoice_id = i.id
                  ORDER BY studio_payments.submitted_at DESC NULLS LAST
                 LIMIT 1) AS last_payment_id
           FROM studio_payments p
          WHERE p.invoice_id = i.id) payment_summary ON true;

