CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION handle_new_user();
CREATE TRIGGER on_auth_user_created_customer AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION handle_new_customer();
CREATE TRIGGER trg_care_bookings_updated_at BEFORE UPDATE ON care_bookings FOR EACH ROW EXECUTE FUNCTION set_updated_at();
CREATE TRIGGER trg_care_queue_picked_up_payment_email AFTER UPDATE OF status ON care_bookings FOR EACH ROW EXECUTE FUNCTION care_queue_picked_up_payment_email();
CREATE TRIGGER trg_care_append_expense_ledger AFTER INSERT ON care_expenses FOR EACH ROW EXECUTE FUNCTION care_append_expense_ledger();
