create policy "Users can create support threads" on public.support_threads as permissive for insert to public with check ((( SELECT auth.uid() AS uid) = user_id));
create policy "Users can update own support threads" on public.support_threads as permissive for update to public using ((( SELECT auth.uid() AS uid) = user_id));
create policy "Users can view own support threads" on public.support_threads as permissive for select to public using ((( SELECT auth.uid() AS uid) = user_id));
create policy support_threads_update_customer_read_pointer on public.support_threads as permissive for update to authenticated using ((user_id = ( SELECT auth.uid() AS uid))) with check ((user_id = ( SELECT auth.uid() AS uid)));
create policy support_threads_update_staff_read_pointer on public.support_threads as permissive for update to authenticated using (is_staff_in(division, NULL::text)) with check (is_staff_in(division, NULL::text));
create policy "Service role full access" on public.trust_flags as permissive for all to public using (true) with check (true);
create policy user_addresses_owner_delete on public.user_addresses as permissive for delete to authenticated using ((user_id = ( SELECT auth.uid() AS uid)));
create policy user_addresses_owner_insert on public.user_addresses as permissive for insert to authenticated with check ((user_id = ( SELECT auth.uid() AS uid)));
create policy user_addresses_owner_select on public.user_addresses as permissive for select to authenticated using ((user_id = ( SELECT auth.uid() AS uid)));
create policy user_addresses_owner_update on public.user_addresses as permissive for update to authenticated using ((user_id = ( SELECT auth.uid() AS uid))) with check ((user_id = ( SELECT auth.uid() AS uid)));
create policy user_addresses_staff_select on public.user_addresses as permissive for select to authenticated using (is_platform_staff());
create policy user_engagement_events_owner_select on public.user_engagement_events as permissive for select to public using ((user_id = ( SELECT auth.uid() AS uid)));
create policy wallet_tx_select_own_v2_d8 on public.wallet_transactions as permissive for select to authenticated using (((profile_id = ( SELECT auth.uid() AS uid)) OR (wallet_id IN ( SELECT wallets.id
   FROM wallets
  WHERE (wallets.profile_id = ( SELECT auth.uid() AS uid))))));
create policy wallets_select_own_v2_d8 on public.wallets as permissive for select to authenticated using ((profile_id = ( SELECT auth.uid() AS uid)));
create policy company_assets_owner_delete on storage.objects as permissive for delete to authenticated using (((bucket_id = 'company-assets'::text) AND (EXISTS ( SELECT 1
   FROM owner_profiles op
  WHERE ((op.user_id = ( SELECT auth.uid() AS uid)) AND (op.is_active = true) AND (op.role = ANY (ARRAY['owner'::text, 'admin'::text])))))));
create policy company_assets_owner_insert on storage.objects as permissive for insert to authenticated with check (((bucket_id = 'company-assets'::text) AND (EXISTS ( SELECT 1
   FROM owner_profiles op
  WHERE ((op.user_id = ( SELECT auth.uid() AS uid)) AND (op.is_active = true) AND (op.role = ANY (ARRAY['owner'::text, 'admin'::text])))))));
create policy company_assets_owner_update on storage.objects as permissive for update to authenticated using (((bucket_id = 'company-assets'::text) AND (EXISTS ( SELECT 1
   FROM owner_profiles op
  WHERE ((op.user_id = ( SELECT auth.uid() AS uid)) AND (op.is_active = true) AND (op.role = ANY (ARRAY['owner'::text, 'admin'::text]))))))) with check (((bucket_id = 'company-assets'::text) AND (EXISTS ( SELECT 1
   FROM owner_profiles op
  WHERE ((op.user_id = ( SELECT auth.uid() AS uid)) AND (op.is_active = true) AND (op.role = ANY (ARRAY['owner'::text, 'admin'::text])))))));
create policy company_assets_public_read on storage.objects as permissive for select to public using ((bucket_id = 'company-assets'::text));
create policy hq_ic_storage_delete on storage.objects as permissive for delete to authenticated using (((bucket_id = 'hq-internal-comms'::text) AND (split_part(name, '/'::text, 2) = (( SELECT auth.uid() AS uid))::text) AND hq_ic_can_write_thread(hq_ic_storage_thread_id_from_path(name))));
create policy hq_ic_storage_insert on storage.objects as permissive for insert to authenticated with check (((bucket_id = 'hq-internal-comms'::text) AND (split_part(name, '/'::text, 2) = (( SELECT auth.uid() AS uid))::text) AND hq_ic_can_write_thread(hq_ic_storage_thread_id_from_path(name))));
create policy hq_ic_storage_select on storage.objects as permissive for select to authenticated using (((bucket_id = 'hq-internal-comms'::text) AND hq_ic_can_read_thread(hq_ic_storage_thread_id_from_path(name))));
create policy hq_ic_storage_update on storage.objects as permissive for update to authenticated using (((bucket_id = 'hq-internal-comms'::text) AND (split_part(name, '/'::text, 2) = (( SELECT auth.uid() AS uid))::text) AND hq_ic_can_write_thread(hq_ic_storage_thread_id_from_path(name)))) with check (((bucket_id = 'hq-internal-comms'::text) AND (split_part(name, '/'::text, 2) = (( SELECT auth.uid() AS uid))::text) AND hq_ic_can_write_thread(hq_ic_storage_thread_id_from_path(name))));

